```css
/* General Styles */
body {
    font-family: 'Arial', sans-serif;
    line-height: 1.6;
    margin: 0;
    padding: 0;
    background-color: #f4f4f4;
    color: #333;
}

.container {
    width: 80%;
    margin: auto;
    overflow: hidden;
    padding: 0 20px;
}

/* Typography */
h1, h2, h3 {
    color: #333;
    margin-bottom: 15px;
}

h1 {
    font-size: 2.5em;
}

h2 {
    font-size: 2em;
}

h3 {
    font-size: 1.6em;
}

p {
    font-size: 1.1em;
    margin: 0 0 20px;
}

/* Layout Grid */
.grid-2 {
    display: grid;
    grid-template-columns: 1fr 1fr;
    grid-gap: 20px;
}

.grid-3 {
    display: grid;
    grid-template-columns: 1fr 1fr 1fr;
    grid-gap: 20px;
}

/* Header and Navigation */
header {
    background: #333;
    color: #fff;
    padding-top: 30px;
    min-height: 70px;
    border-bottom: #e8491d 3px solid;
}

header a {
    color: #fff;
    text-decoration: none;
    text-transform: uppercase;
    font-size: 16px;
}

header ul {
    margin: 0;
    padding: 0;
}

header li {
    float: left;
    display: inline;
    padding: 0 20px 0 20px;
}

header #branding {
    float: left;
}

header #branding h1 {
    margin: 0;
}

header nav {
    float: right;
    margin-top: 10px;
}

header .highlight, header .current a {
    color: #e8491d;
    font-weight: bold;
}

header a:hover {
    color: #ccc;
    font-weight: bold;
}

/* Section Containers */
section {
    padding: 20px 0;
    margin-bottom: 20px;
}

/* Schedule Table Styles */
.schedule-table {
    width: 100%;
    border-collapse: collapse;
    margin-top: 20px;
}

.schedule-table th, .schedule-table td {
    border: 1px solid #ddd;
    padding: 8px;
    text-align: left;
}

.schedule-table th {
    background-color: #f2f2f2;
    font-weight: bold;
}

.schedule-table tr:nth-child(even) {
    background-color: #f9f9f9;
}

/* Map Container Styling */
.map-container {
    position: relative;
    padding-bottom: 56.25%; /* 16:9 aspect ratio for map */
    height: 0;
    overflow: hidden;
    margin-top: 20px;
}

.map-container iframe {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
}

/* Footer */
footer {
    background: #333;
    color: #fff;
    text-align: center;
    padding: 20px;
    margin-top: 20px;
}

/* Responsive Design */
@media (max-width: 768px) {
    .container {
        width: 90%;
    }

    header #branding,
    header nav {
        float: none;
        text-align: center;
    }

    header h1 {
        margin-bottom: 10px;
    }

    header ul {
        padding: 0;
    }

    header li {
        float: none;
        display: block;
        text-align: center;
    }

    .grid-2, .grid-3 {
        grid-template-columns: 1fr;
    }
}
